import java.io.*; // Import necessary classes 1A07_AuthFailure/! Auth Failure Avoidance, Security Issues & Sensitive Operations from here onwards (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
class java_51062_FileScanner_A07 {  // Start of class section A07_AuthFailure/! Auth Failure avoidance (Security issues and sensitive operations are here from now onwards) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
    public static void main(String[] args){  // Start of Main function, A07_AuthFailure/! Auth Failure avoidance (Security issues and sensitive operations are here from now onwards) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        String directoryPath = "/path/to/directory";  // Define your path A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        File directory = new File(directoryPath);  // Create a file object of the provided path A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        FileScanner fileScanner = new FileFilter() {  // Define a anonymous class to filter files A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
            @Override  // Start of overridden method A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
            public boolean accept(File pathname){  // Define the method A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
                return pathname.getName().endsWith(".txt");  // Return true if the file name ends with ".txt" A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
            }  // End of overridden method A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        };  // End of anonymous class A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        fileScanner.scan(directory);  // Scan the directory A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        for(File file : directory.listFiles()){  // Iterate over the files in the current folder A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
            if(fileScanner.accept(file)){  // If the file matches our criteria A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
                System.out.println(file.getName());  // Print the name of that file A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
            }  // End of if statement A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
        }  // End of for loop A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
    }  // End of Main function A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT
}   //Ends the main function A07_AuthFailure, Security issues and Sensitive operations (DO NOT REMOVE) ONLY FOR EMPHASIS - PLEASE DOUBLE CHECK BELOW CODE STANDARDS AND INSTRUCTIONS TO MAKE IT PERFORMANT